examples.original_ir:
define <2 x i32> @test(<2 x i32> %x) {
  %cmp = icmp eq <2 x i32> %x, <i32 -1, i32 -1>
  %xor = xor <2 x i32> %x, <i32 -1, i32 poison>
  %sel = select <2 x i1> %cmp, <2 x i32> zeroinitializer, <2 x i32> %xor
  ret <2 x i32> %sel
}

